+}
+
+impl MatrixNormOrder {
+    pub fn from_token(token: &str) -> Result<Self, LinAlgError> {
+        match token.trim().to_ascii_lowercase().as_str() {
+            "fro" | "f" => Ok(Self::Fro),
+            "1" => Ok(Self::One),
+            "inf" | "+inf" => Ok(Self::Inf),
+            "2" => Ok(Self::Two),
+            "-2" => Ok(Self::NegTwo),
+            "nuc" => Ok(Self::Nuclear),
+            _ => Err(LinAlgError::NormDetRankPolicyViolation(
+                "unsupported matrix norm order token",
+            )),
+        }
+    }
+}
